@@ -43376,7 +43376,9 @@ impl Connection {
         // commit seq advances on every commit but the schema cookie does not.
         // When we already hold schema metadata at this cookie AND we are not
         // eagerly hydrating row data (the file-backed strict-no-mem-fallback
-        // case), the costly sqlite_master scan below produces an image
+        // case, which is the whole reason file-backed reads traverse the
+        // pager rather than the MemDatabase), the costly sqlite_master scan
+        // plus `parse_record` allocation chain below produce an image
         // identical to what's already cached. Skip it and just bump the
         // visibility tracking so the next read boundary still observes the
         // refreshed pager snapshot.
@@ -43386,10 +43388,18 @@ impl Connection {
         // zero-header path (which has its own early return above). Schema
         // changes always bump schema_cookie so any CREATE/ALTER/DROP will
         // take the full scan path below.
+        //
+        // `memdb_rows_loaded` is intentionally NOT checked: when
+        // hydrate_rows=false the full path itself never scans user table
+        // rows (see the `should_scan_rows` gate further down), so the
+        // memdb's row image is stable across reloads regardless of whether
+        // the loaded flag is set. Gating on it would make this fast path
+        // fire only on the first ever reload (after which the flag is set
+        // unconditionally at the bottom of this function), which defeats
+        // the purpose on long-lived connections.
         if !hydrate_rows
             && schema_cookie != 0
             && schema_cookie == *self.schema_cookie.borrow()
-            && !self.memdb_rows_loaded.get()
             && !self.memdb_requires_active_txn_reload.get()
             && self.pending_memdb_direct_upserts.borrow().is_empty()
             && !self.pending_local_live_vtab_preserve_once.get()
